#!/usr/bin/env python3
"""Build canonical chunk-grounded LangSmith seed testsets.

The JSONL rows are evaluator input. The sidecar evidence_map.json is an
authoring/verification aid and is not loaded by LangSmith evaluators.
"""

from __future__ import annotations

import argparse
import json
from pathlib import Path
from typing import Any

OUT = Path("data/testsets/langsmith")


def jdump(path: Path, rows: list[dict[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("".join(json.dumps(row, ensure_ascii=False, separators=(",", ":")) + "\n" for row in rows), encoding="utf-8")


def meta(party: str | None = None, location: str | None = None) -> dict[str, Any]:
    return {"party_type": party, "location": location}


def filt(party: str | None = None, location: str | None = None) -> dict[str, Any] | None:
    parts = []
    if party:
        parts.append({"party_type": party})
    if location:
        parts.append({"location": location})
    if not parts:
        return None
    if len(parts) == 1:
        return parts[0]
    return {"$and": parts}


def ratio(a: int, b: int) -> dict[str, int]:
    return {"a": a, "b": b}


