SUITE_ROWS={"intake":INTAKE,"router":ROUTER,"metadata_filter":FILTERS,"retrieval":RETRIEVAL,"reranker":RERANKER,"multiturn":MULTITURN,"structured_output":STRUCTURED}
SUITE_FILES={"intake":"intake_eval.jsonl","router":"router_eval.jsonl","metadata_filter":"metadata_filter_eval.jsonl","retrieval":"retrieval_eval.jsonl","reranker":"reranker_eval.jsonl","multiturn":"multiturn_eval.jsonl","structured_output":"structured_output_eval.jsonl"}


def write_readme() -> None:
    (OUT / "README.md").write_text("""# LangSmith Testsets\n\nThese JSONL files evaluate internal RAG decisions, not final answer prose.\n\nCanonical evidence source: `data/chunks/upstage/custom/chunks.json`. Legacy q1/q2/q3 datasets are wording hints only. Expected diagram IDs, evidence keywords, ratios, modifiers, and cross-references must be traceable to chunk `page_content` and metadata.\n\nRun validation:\n\n```bash\npython3 evaluation/validate_langsmith_testsets.py\n```\n""", encoding="utf-8")


def write_manifest(suites: list[str]) -> None:
    manifest={"canonical_source":"data/chunks/upstage/custom/chunks.json","legacy_sources":"wording hints only","suites":{s:{"file":SUITE_FILES[s],"rows":len(SUITE_ROWS[s])} for s in suites}}
    (OUT / "manifest.json").write_text(json.dumps(manifest, ensure_ascii=False, indent=2)+"\n", encoding="utf-8")


def update_evidence_map(suites: list[str]) -> None:
    evidence={}
    for s in suites:
        for row in SUITE_ROWS[s]:
            ids=[]
            for f in ("expected_diagram_ids","acceptable_diagram_ids","near_miss_diagram_ids","expected_reference_diagram_ids","expected_unfiltered_diagram_ids"):
                ids.extend(row.get(f,[]) or [])
            evidence[row["id"]]={"suite":s,"chunk_grounding":"expected labels must be checked against data/chunks/upstage/custom/chunks.json page_content","diagram_ids":sorted(set(ids)),"evidence_terms":row.get("expected_evidence_keywords") or row.get("required_evidence") or []}
    (OUT / "evidence_map.json").write_text(json.dumps(evidence, ensure_ascii=False, indent=2)+"\n", encoding="utf-8")


def parse_args() -> argparse.Namespace:
    p=argparse.ArgumentParser()
    p.add_argument("--suite", choices=list(SUITE_ROWS)+["all"], default="all")
    return p.parse_args()


def main() -> int:
    args=parse_args()
    suites=list(SUITE_ROWS) if args.suite=="all" else [args.suite]
    OUT.mkdir(parents=True, exist_ok=True)
    for s in suites:
        jdump(OUT / SUITE_FILES[s], SUITE_ROWS[s])
        print(f"wrote {s}: {len(SUITE_ROWS[s])}")
    existing=[name for name,file in SUITE_FILES.items() if (OUT/file).exists()]
    write_readme()
    write_manifest(existing)
    update_evidence_map(existing)
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
